import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.DXGyWiRo.js";const i="/assets/image%20(46).DNVaZN1h.",m=JSON.parse('{"title":"Pelias Geocoder","description":"","frontmatter":{},"headers":[],"relativePath":"gis/pelias-geocoder/README.md","filePath":"gis/pelias-geocoder/README.md"}'),l={name:"gis/pelias-geocoder/README.md"};function n(s,e,c,d,p,u){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="pelias-geocoder" tabindex="-1">Pelias Geocoder <a class="header-anchor" href="#pelias-geocoder" aria-label="Permalink to &quot;Pelias Geocoder&quot;">​</a></h1><p><a href="https://raw.githubusercontent.com/pelias/design/master/logo/pelias_github/Github_markdown_hero.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p><a href="./#a-modular-open-source-search-engine-for-our-world"><strong>hashtag</strong></a> <strong>A modular, open-source search engine for our world.</strong></p><p>Pelias is a geocoder powered completely by open data, available freely to everyone.</p><p><a href="https://en.wikipedia.org/wiki/MIT_License" target="_blank" rel="noreferrer"><img src="https://camo.githubusercontent.com/74cadc0f6e1f2b9d0386d40e4dfa47a73184b33bbcac8987ec027455e2238d52/68747470733a2f2f696d672e736869656c64732e696f2f6769746875622f6c6963656e73652f70656c6961732f6170693f7374796c653d666c617426636f6c6f723d6f72616e6765" alt=""></a> <a href="https://hub.docker.com/u/pelias" target="_blank" rel="noreferrer"><img src="https://camo.githubusercontent.com/fc6e5009dc1c4a8aa73ba3b7b2ef1c591ed6036f5d6294d2549ec04cbbd2c4f7/68747470733a2f2f696d672e736869656c64732e696f2f646f636b65722f70756c6c732f70656c6961732f6170693f7374796c653d666c617426636f6c6f723d696e666f726d6174696f6e616c" alt=""></a> <a href="https://gitter.im/pelias/pelias" target="_blank" rel="noreferrer"><img src="https://camo.githubusercontent.com/7db7ba842eb3e6673459b555286f6222f396849704d97a24c59bae3468cfe4e0/68747470733a2f2f696d672e736869656c64732e696f2f6769747465722f726f6f6d2f70656c6961732f70656c6961733f7374796c653d666c617426636f6c6f723d79656c6c6f77" alt=""></a></p><p>Local Installation: <a href="https://github.com/pelias/docker" target="_blank" rel="noreferrer">https://github.com/pelias/docker</a> · Cloud Webservice: <a href="https://geocode.earth/" target="_blank" rel="noreferrer">https://geocode.earth/</a> · Documentation: <a href="https://github.com/pelias/documentation" target="_blank" rel="noreferrer">https://github.com/pelias/documentation</a> · Community Chat: <a href="https://gitter.im/pelias/pelias" target="_blank" rel="noreferrer">https://gitter.im/pelias/pelias</a></p><p>What is Pelias?</p><p>Pelias is a search engine for places worldwide, powered by open data. It turns addresses and place names into geographic coordinates, and turns geographic coordinates into places and addresses. With Pelias, you’re able to turn your users’ place searches into actionable geodata and transform your geodata into real places.</p><p>We think open data, open source, and open strategy win over proprietary solutions at any part of the stack and we want to ensure the services we offer are in line with that vision. We believe that an open geocoder improves over the long-term only if the community can incorporate truly representative local knowledge.</p><h2 id="pelias-documentation" tabindex="-1">Pelias Documentation <a class="header-anchor" href="#pelias-documentation" aria-label="Permalink to &quot;Pelias Documentation&quot;">​</a></h2><p>Here is where you can find all documentation for the <a href="https://github.com/pelias/pelias/" target="_blank" rel="noreferrer">Pelias geocoder</a>.</p><h3 id="core-features-and-api-documentation" tabindex="-1">Core Features and API Documentation <a class="header-anchor" href="#core-features-and-api-documentation" aria-label="Permalink to &quot;Core Features and API Documentation&quot;">​</a></h3><p>Endpoint descriptions</p><ul><li><a href="https://github.com/pelias/documentation/blob/master/search.md" target="_blank" rel="noreferrer">Forward geocoding</a> (/v1/search) — find a place by searching for an address or name</li><li><a href="https://github.com/pelias/documentation/blob/master/reverse.md" target="_blank" rel="noreferrer">Reverse geocoding</a> (/v1/reverse) — find what is located at a certain coordinate location</li><li><a href="https://github.com/pelias/documentation/blob/master/autocomplete.md" target="_blank" rel="noreferrer">Autocomplete</a> (/v1/autocomplete) — give real-time result suggestions without having to type the whole location</li><li><a href="https://github.com/pelias/documentation/blob/master/structured-geocoding.md" target="_blank" rel="noreferrer">Structured Geocoding</a> (/v1/search/structured) (beta) — find a place with data already separated into housenumber, street, city, etc</li><li><a href="https://github.com/pelias/documentation/blob/master/place.md" target="_blank" rel="noreferrer">Place endpoint</a> (/v1/place) — details on a place returned from a previous query</li></ul><p><em>Not sure which Endpoint to use? We have a</em> <a href="https://github.com/pelias/documentation/blob/master/search-workflows.md" target="_blank" rel="noreferrer">page</a> <em>for that</em></p><p>Query parameters and options</p><ul><li><a href="https://github.com/pelias/documentation/blob/master/search.md#prioritize-results-by-proximity" target="_blank" rel="noreferrer">Global coverage with prioritized local results</a></li><li><a href="https://github.com/pelias/documentation/blob/master/language-codes.md" target="_blank" rel="noreferrer">Language support</a> — see results in different languages</li></ul><p>Response Properties</p><ul><li><a href="https://github.com/pelias/documentation/blob/master/response.md" target="_blank" rel="noreferrer">Full list of response properties</a></li><li><a href="https://github.com/pelias/documentation/blob/master/result_quality.md" target="_blank" rel="noreferrer">Confidence scores, match_types and other tools for determining result quality</a></li></ul><h3 id="data-sources" tabindex="-1">Data Sources <a class="header-anchor" href="#data-sources" aria-label="Permalink to &quot;Data Sources&quot;">​</a></h3><ul><li><a href="https://github.com/pelias/documentation/blob/master/data-sources.md" target="_blank" rel="noreferrer">Pelias data sources</a></li></ul><h3 id="running-your-own-pelias" tabindex="-1">Running your own Pelias <a class="header-anchor" href="#running-your-own-pelias" aria-label="Permalink to &quot;Running your own Pelias&quot;">​</a></h3><ul><li><a href="https://github.com/pelias/documentation/blob/master/getting_started_install.md" target="_blank" rel="noreferrer">Getting started</a> — Start here if you&#39;re looking to install Pelias</li><li><a href="https://github.com/pelias/documentation/blob/master/pelias_from_scratch.md" target="_blank" rel="noreferrer">Pelias from scratch</a> — More in-depth instructions for installing Pelias</li><li><a href="https://github.com/pelias/documentation/blob/master/full_planet_considerations.md" target="_blank" rel="noreferrer">Full planet build considerations</a> — Special information on running a full planet Pelias build</li><li><a href="https://github.com/pelias/documentation/blob/master/services.md" target="_blank" rel="noreferrer">Service descriptions</a> — A description of all the Pelias services, and when they are used</li><li><a href="https://github.com/pelias/documentation/blob/master/requirements.md" target="_blank" rel="noreferrer">Software Requirements</a> — A list of all software requirements for Pelias</li></ul><h3 id="pelias-project-development" tabindex="-1">Pelias project development <a class="header-anchor" href="#pelias-project-development" aria-label="Permalink to &quot;Pelias project development&quot;">​</a></h3><ul><li><a href="https://github.com/pelias/documentation/blob/master/release-notes.md" target="_blank" rel="noreferrer">Release notes</a> — See notable changes in Pelias over time</li><li><a href="https://github.com/pelias/documentation/blob/master/development/roadmap.md" target="_blank" rel="noreferrer">Development roadmap</a> — Plans for future improvements to Pelias</li></ul><h3 id="misc" tabindex="-1">Misc <a class="header-anchor" href="#misc" aria-label="Permalink to &quot;Misc&quot;">​</a></h3><ul><li><a href="https://github.com/pelias/documentation/blob/master/glossary.md" target="_blank" rel="noreferrer">Glossary of common terms</a></li></ul><p>Last updated 3 years ago</p>',28)])])}const f=a(l,[["render",n]]);export{m as __pageData,f as default};
